import json, uuid, redis, os
from anthropic import Anthropic
from dataclasses import dataclass, asdict, field
from enum import Enum

r = redis.Redis.from_url(os.environ.get("REDIS_URL", "redis://localhost:6379"), decode_responses=True)
client = Anthropic()

class TaskStatus(str, Enum):
    PENDING   = "pending"
    RUNNING   = "running"
    DONE      = "done"
    FAILED    = "failed"

@dataclass
class Task:
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    description: str = ""
    status: str = TaskStatus.PENDING
    result: str | None = None
    error:  str | None = None

def plan_tasks(goal: str) -> list[Task]:
    """Use the LLM to decompose the goal into a list of tasks."""
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        messages=[{
            "role": "user",
            "content": (
                f"Decompose this goal into 3-6 sequential tasks.\nGoal: {goal}\n\n"
                "Respond with JSON: [{"description": "..."}] only."
            )
        }]
    )
    try:
        raw = json.loads(resp.content[0].text)
        return [Task(description=item["description"]) for item in raw]
    except (json.JSONDecodeError, KeyError):
        return [Task(description=goal)]   # fallback: single task

def save_task(task: Task) -> None:
    r.hset("tasks", task.id, json.dumps(asdict(task)))

def load_all_tasks() -> list[Task]:
    raw = r.hgetall("tasks")
    return [Task(**json.loads(v)) for v in raw.values()]

def enqueue_pending_tasks(tasks: list[Task]) -> None:
    for t in tasks:
        if t.status == TaskStatus.PENDING:
            r.rpush("task_queue", t.id)   # executor picks from this queue

def planner_run(goal: str) -> None:
    tasks = plan_tasks(goal)
    for t in tasks:
        save_task(t)
    enqueue_pending_tasks(tasks)
    print(f"Planned {len(tasks)} tasks for goal: {goal}")

import json, time, redis, os
from anthropic import Anthropic
from dataclasses import asdict

r = redis.Redis.from_url(os.environ.get("REDIS_URL", "redis://localhost:6379"), decode_responses=True)
client = Anthropic()

EXECUTOR_TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web.",
        "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
    },
    {
        "name": "write_file",
        "description": "Write content to a file.",
        "input_schema": {"type": "object", "properties": {"filename": {"type": "string"}, "content": {"type": "string"}}, "required": ["filename", "content"]},
    },
]

def execute_tool(name: str, inputs: dict) -> str:
    if name == "web_search":
        return json.dumps({"results": [f"Result for: {inputs['query']}"]})
    if name == "write_file":
        # In production: write to object storage scoped to the run
        return json.dumps({"written": inputs["filename"], "bytes": len(inputs["content"])})
    return json.dumps({"error": "unknown"})

def run_task(task_id: str) -> None:
    raw = r.hget("tasks", task_id)
    if not raw:
        return
    task = Task(**json.loads(raw))
    task.status = TaskStatus.RUNNING
    save_task(task)

    messages = [{"role": "user", "content": f"Complete this task: {task.description}"}]
    try:
        for _ in range(10):   # step limit
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=800,
                tools=EXECUTOR_TOOLS,
                messages=messages,
            )
            if resp.stop_reason == "end_turn":
                result = next((b.text for b in resp.content if b.type == "text"), "")
                task.result = result
                task.status = TaskStatus.DONE
                break
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    res = execute_tool(block.name, block.input)
                    tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": res})
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]
        else:
            task.status = TaskStatus.FAILED
            task.error = "Step limit reached"
    except Exception as exc:
        task.status = TaskStatus.FAILED
        task.error = str(exc)
    save_task(task)

def executor_loop() -> None:
    print("Executor started — polling task queue...")
    while True:
        task_id = r.blpop("task_queue", timeout=5)
        if task_id:
            run_task(task_id[1])
        else:
            time.sleep(1)

import uuid, time, redis

r = redis.Redis.from_url("redis://localhost:6379", decode_responses=True)

HIGH_STAKES_ACTIONS = {"send_email", "delete_record", "make_payment", "deploy_code"}

def request_human_approval(action: str, details: dict, timeout_seconds: int = 3600) -> bool:
    """
    Block until a human approves or rejects the action, or until timeout.
    Returns True if approved, False if rejected or timed out.
    """
    approval_id = str(uuid.uuid4())
    r.hset("approvals", approval_id, json.dumps({
        "action": action,
        "details": details,
        "status": "pending",
    }))
    # In production: send Slack message, email, or push notification with approval_id
    print(f"\nAPPROVAL REQUIRED [{approval_id}]:\nAction: {action}\nDetails: {json.dumps(details, indent=2)}")
    print(f"To approve: redis-cli hset approvals {approval_id} '{{"status":"approved"}}'\n")

    deadline = time.time() + timeout_seconds
    while time.time() < deadline:
        raw = r.hget("approvals", approval_id)
        if raw:
            data = json.loads(raw)
            if data.get("status") == "approved":
                return True
            if data.get("status") == "rejected":
                return False
        time.sleep(5)
    return False   # timed out → treat as rejected

def safe_execute_tool(name: str, inputs: dict) -> str:
    if name in HIGH_STAKES_ACTIONS:
        approved = request_human_approval(name, inputs)
        if not approved:
            return json.dumps({"error": "action_rejected_by_human"})
    return execute_tool(name, inputs)
